export default {
    props: {},
    components: {},
    mixins: [],
    data: function () {
        return {
            currentDate: null,
            currentTime: null,
        };
    },
    watch: {},
    computed: {},
    created: function () {
        this.currentDate = this.moment().format('DD MMMM YYYY');
        this.currentTime = this.moment().tz("Asia/Singapore").format('h:mm:ss A');
        setInterval(() => this.updateCurrentTime(), 1 * 1000);

    },
    beforeDestroy: function () { },
    mounted: function () { },
    methods: {
        updateCurrentTime() {
            this.currentDate = this.moment().format('DD MMMM YYYY');
            this.currentTime = this.moment().tz("Asia/Singapore").format('h:mm:ss A');
        }
    },
}
